- (void)groMoreBannerAdLoad {
    // Remove previous ad
    [self.bannerAdView removeFromSuperview];

    // Reconfigure and load ad
    CGFloat bannerHeight = self.bannerAdHeight;
    CGFloat bannerWidth = [UIScreen mainScreen].bounds.size.width;
    CGSize adSize = CGSizeMake(bannerWidth, bannerHeight);
    BUAdSlot *slot = [[BUAdSlot alloc] init];
    slot.ID = [AdManager sharedManager].adModel.bannerSlotId;
    BUNativeExpressBannerView *bannerView = [[BUNativeExpressBannerView alloc] initWithSlot:slot rootViewController:self adSize:adSize];
    bannerView.delegate = self;
    self.bannerAdView = bannerView;
    [self.bannerAdView loadAdData];
}

