#pragma mark - UISearchBar Delegate
- (void)searchBar:(UISearchBar *)searchBar textDidChange:(NSString *)searchText {

    NSPredicate *predicate = [NSPredicate predicateWithFormat:@"name CONTAINS[cd] %@ OR note CONTAINS[cd] %@", searchText, searchText];
    NSArray *filteredArray = [[AccountModel allAccs] filteredArrayUsingPredicate:predicate];
    self.displayAccs = [filteredArray mutableCopy];
    [self.collectionView reloadData];

}

- (void)searchBarSearchButtonClicked:(UISearchBar *)searchBar {
    [searchBar resignFirstResponder];
}

#pragma mark - Lazy Loading
- (ShowHeaderView *)headerView {
    if (_headerView == nil) {
        _headerView = [[ShowHeaderView alloc] init];
        _headerView.titleLabel.text = self.text;
        _headerView.titleLabel.textColor = BLACK_COLOR;
        _headerView.editButton.hidden = YES;
    }
    return _headerView;
}

- (UISearchBar *)searchBar {
    if (!_searchBar) {
        _searchBar = [[UISearchBar alloc] init];
        _searchBar.placeholder = NSLocalizedString(@"搜索", nil);
        _searchBar.delegate = self;
        _searchBar.backgroundImage = [[UIImage alloc] init];

        UITextField *searchField = _searchBar.searchTextField;
        if (searchField) {
            searchField.backgroundColor = RGBA(245, 245, 245, 1);
        }
    }
    return _searchBar;
}

- (UICollectionView *)collectionView {
    if (!_collectionView) {
        UICollectionViewFlowLayout *layout = [[UICollectionViewFlowLayout alloc] init];
        layout.scrollDirection = UICollectionViewScrollDirectionVertical;
        layout.minimumLineSpacing = 0;
        layout.minimumInteritemSpacing = 0;

        _collectionView = [[UICollectionView alloc] initWithFrame:CGRectZero collectionViewLayout:layout];
        _collectionView.dataSource = self;
        _collectionView.delegate = self;
        _collectionView.backgroundColor = [UIColor clearColor];
        _collectionView.alwaysBounceVertical = YES;
        _collectionView.keyboardDismissMode = UIScrollViewKeyboardDismissModeOnDrag;

        [_collectionView registerClass:[AccCell class] forCellWithReuseIdentifier:@"AccCell"];
    }
    return _collectionView;
}

@end

