    UIColor *baseColor = RGBA(249, 251, 255, 1);
    [baseColor setFill];
    CGContextFillRect(context, CGRectMake(0, 0, size.width, size.height));

    CGColorSpaceRef colorSpace = CGColorSpaceCreateDeviceRGB();
    NSArray *colors = @[(__bridge id)RGBA(255, 188, 232, 0.85).CGColor,
                        (__bridge id)RGBA(198, 234, 255, 0.25).CGColor,
                        (__bridge id)RGBA(170, 232, 246, 0.55).CGColor];
    CGFloat locations[] = {0, 0.45, 1};
    CGGradientRef gradient = CGGradientCreateWithColors(colorSpace, (__bridge CFArrayRef)colors, locations);
    CGContextDrawLinearGradient(context, gradient, CGPointZero, CGPointMake(size.width, size.height), 0);
    CGGradientRelease(gradient);
    CGColorSpaceRelease(colorSpace);

    [RGBA(255, 122, 205, 0.28) setFill];
    UIBezierPath *leftShape = [UIBezierPath bezierPathWithRoundedRect:CGRectMake(-ZOOMW(18), ZOOMW(12), ZOOMW(132), ZOOMW(72)) cornerRadius:ZOOMW(30)];
