    [rightBlob fill];

    [RGBA(123, 195, 255, 0.16) setFill];
    UIBezierPath *rightGlow = [UIBezierPath bezierPathWithOvalInRect:CGRectMake(size.width - ZOOMW(108), ZOOMW(44), ZOOMW(92), ZOOMW(120))];
    [rightGlow fill];

    UIImage *image = UIGraphicsGetImageFromCurrentImageContext();
    UIGraphicsEndImageContext();
    return image;
