            [bigCard setBackgroundImage:[UIImage imageNamed:[NSString stringWithFormat:@"A_%@", self.displaytypes[0].type]] forState:UIControlStateNormal];
            bigCard.imageView.contentMode = UIViewContentModeScaleToFill;
            [bigCard addTarget:self action:@selector(headerCardTapped:) forControlEvents:UIControlEventTouchUpInside];
            [header addSubview:bigCard];

            // 右上小卡片
            UIButton *topRightCard = [UIButton buttonWithType:UIButtonTypeCustom];
            topRightCard.tag = 1;
            [topRightCard setBackgroundImage:[UIImage imageNamed:[NSString stringWithFormat:@"A_%@", self.displaytypes[1].type]] forState:UIControlStateNormal];
            topRightCard.imageView.contentMode = UIViewContentModeScaleToFill;
            [topRightCard addTarget:self action:@selector(headerCardTapped:) forControlEvents:UIControlEventTouchUpInside];
            [header addSubview:topRightCard];

            // 右下小卡片
            UIButton *bottomRightCard = [UIButton buttonWithType:UIButtonTypeCustom];
            bottomRightCard.tag = 2;
            [bottomRightCard setBackgroundImage:[UIImage imageNamed:[NSString stringWithFormat:@"A_%@", self.displaytypes[2].type]] forState:UIControlStateNormal];
            bottomRightCard.imageView.contentMode = UIViewContentModeScaleToFill;
            [bottomRightCard addTarget:self action:@selector(headerCardTapped:) forControlEvents:UIControlEventTouchUpInside];
            [header addSubview:bottomRightCard];

            [bigCard mas_makeConstraints:^(MASConstraintMaker *make) {
                make.left.equalTo(header).offset(padding);
                make.top.equalTo(header);
                make.width.mas_equalTo(halfWidth);
                make.height.mas_equalTo(bigHeight);
            }];

            [topRightCard mas_makeConstraints:^(MASConstraintMaker *make) {
                make.right.equalTo(header).offset(-padding);
                make.top.equalTo(header);
                make.width.mas_equalTo(halfWidth);
                make.height.mas_equalTo(smallHeight);
            }];

            [bottomRightCard mas_makeConstraints:^(MASConstraintMaker *make) {
                make.right.equalTo(header).offset(-padding);
                make.top.equalTo(topRightCard.mas_bottom).offset(vSpacing);
                make.width.mas_equalTo(halfWidth);
                make.height.mas_equalTo(smallHeight);
            }];
        }

        return header;
    }
    return [[UICollectionReusableView alloc] init];
}

