@implementation AccountViewController

- (instancetype)init {
    self = [super init];
    if (self) {
        self.view.backgroundColor = WHITE_COLOR;
        self.modalPresentationStyle = UIModalPresentationFullScreen;
        self.orderedTypeKeys = @[@"社交", @"邮箱", @"游戏", @"工作"];
        self.displayTypes = [self orderedDisplayTypes];
#if ENABLE_FEATURE_A
        self.bannerAdHeight = ZOOM(75);
#endif
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = WHITE_COLOR;
    self.navigationItem.title = @"";
    self.navigationItem.rightBarButtonItem = nil;
    [self setupUI];
}

#if ENABLE_FEATURE_A
- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
    [self groMoreBannerAdLoad];
}
#endif

- (NSArray<TypeModel *> *)orderedDisplayTypes {
    NSArray<TypeModel *> *allTypes = [TypeModel allTypes];
    NSMutableArray<TypeModel *> *result = [NSMutableArray array];

    for (NSString *typeName in self.orderedTypeKeys) {
        NSPredicate *predicate = [NSPredicate predicateWithFormat:@"type == %@", typeName];
        TypeModel *matchedType = [[allTypes filteredArrayUsingPredicate:predicate] firstObject];
        if (matchedType) {
            [result addObject:matchedType];
        }
    }

    return result.copy;
}

- (void)setupUI {
    [self.view addSubview:self.topBackgroundView];
    [self.view addSubview:self.titleLabel];
    [self.view addSubview:self.topActionButton];
    [self.view addSubview:self.collectionView];
    [self.view addSubview:self.addButton];

    [self.topBackgroundView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.left.right.equalTo(self.view);
        make.height.mas_equalTo(ZOOMW(132));
    }];

    [self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view.mas_safeAreaLayoutGuideTop).offset(ZOOMW(8));
        make.left.equalTo(self.view).offset(ZOOMW(8));
    }];

    [self.topActionButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.titleLabel);
        make.right.equalTo(self.view).offset(ZOOMW(-12));
        make.width.height.mas_equalTo(ZOOMW(28));
    }];

    [self.addButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.view).offset(ZOOMW(8));
        make.right.equalTo(self.view).offset(ZOOMW(-8));
        make.bottom.equalTo(self.view.mas_safeAreaLayoutGuideBottom).offset(ZOOMW(-18));
        make.height.mas_equalTo(ZOOMW(40));
    }];

    [self.collectionView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.topBackgroundView.mas_bottom).offset(ZOOMW(-8));
        make.left.right.equalTo(self.view);
        make.bottom.equalTo(self.addButton.mas_top).offset(ZOOMW(-18));
    }];
}

#pragma mark - Actions

- (void)addNewAcc {
