- (NSDictionary<NSString *, NSString *> *)displayInfoForTypeName:(NSString *)typeName {
    NSDictionary<NSString *, NSDictionary<NSString *, NSString *> *> *mapping = @{
        @"社交": @{ @"title": @"Social", @"subtitle": @"Social Apps", @"image": @"A_Social" },
        @"邮箱": @{ @"title": @"Mail", @"subtitle": @"Various email", @"image": @"A_Mail" },
        @"游戏": @{ @"title": @"Game", @"subtitle": @"Game account", @"image": @"A_Game" },
        @"工作": @{ @"title": @"Work", @"subtitle": @"Work account", @"image": @"A_Work" }
    };
    return mapping[typeName] ?: @{};
