#pragma mark - UICollectionView

- (NSInteger)numberOfSectionsInCollectionView:(UICollectionView *)collectionView {
    return 1;
}

- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.displayTypes.count;
}

- (__kindof UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    AccTypeCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"AccTypeCell" forIndexPath:indexPath];
    TypeModel *type = self.displayTypes[indexPath.item];
    NSDictionary<NSString *, NSString *> *displayInfo = [self displayInfoForTypeName:type.type];
    [cell configureWithTitle:displayInfo[@"title"] ?: type.type
                    subtitle:displayInfo[@"subtitle"] ?: @""
                   imageName:displayInfo[@"image"] ?: @""];
    return cell;
}

