- (UIImageView *)topBackgroundView {
    if (!_topBackgroundView) {
        _topBackgroundView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"A_topBack"]];
        _topBackgroundView.contentMode = UIViewContentModeScaleToFill;
        _topBackgroundView.clipsToBounds = YES;
    }
    return _topBackgroundView;
}

- (UILabel *)titleLabel {
    if (!_titleLabel) {
        _titleLabel = [[UILabel alloc] init];
        _titleLabel.text = @"Dual Accounts";
        _titleLabel.font = KEEPASS_FONT_BOLD(18);
        _titleLabel.textColor = RGBA(68, 68, 68, 1);
    }
    return _titleLabel;
}

- (UIButton *)topActionButton {
    if (!_topActionButton) {
        _topActionButton = [UIButton buttonWithType:UIButtonTypeCustom];
        if (@available(iOS 13.0, *)) {
            UIImageSymbolConfiguration *config = [UIImageSymbolConfiguration configurationWithPointSize:ZOOMW(18) weight:UIImageSymbolWeightRegular];
            [_topActionButton setImage:[UIImage systemImageNamed:@"person.badge.plus" withConfiguration:config] forState:UIControlStateNormal];
            _topActionButton.tintColor = BLACK_COLOR;
        } else {
            [_topActionButton setTitle:@"+" forState:UIControlStateNormal];
            [_topActionButton setTitleColor:BLACK_COLOR forState:UIControlStateNormal];
        }
        [_topActionButton addTarget:self action:@selector(topActionTapped) forControlEvents:UIControlEventTouchUpInside];
    }
    return _topActionButton;
}

- (UIButton *)addButton {
    if (!_addButton) {
        _addButton = [UIButton buttonWithType:UIButtonTypeCustom];
        _addButton.backgroundColor = BUTTON_COLOR;
        _addButton.layer.cornerRadius = ZOOMW(20);
        _addButton.layer.masksToBounds = YES;
        _addButton.titleLabel.font = KEEPASS_FONT_BOLD(16);
        [_addButton setTitle:@"Add account" forState:UIControlStateNormal];
        [_addButton setTitleColor:WHITE_COLOR forState:UIControlStateNormal];
        [_addButton addTarget:self action:@selector(addNewAcc) forControlEvents:UIControlEventTouchUpInside];
    }
    return _addButton;
}

- (UICollectionView *)collectionView {
    if (!_collectionView) {
        UICollectionViewFlowLayout *layout = [[UICollectionViewFlowLayout alloc] init];
        layout.scrollDirection = UICollectionViewScrollDirectionVertical;

        _collectionView = [[UICollectionView alloc] initWithFrame:CGRectZero collectionViewLayout:layout];
        _collectionView.dataSource = self;
        _collectionView.delegate = self;
        _collectionView.backgroundColor = CLEAR_COLOR;
        _collectionView.alwaysBounceVertical = YES;
        _collectionView.showsVerticalScrollIndicator = NO;
        [_collectionView registerClass:[AccTypeCell class] forCellWithReuseIdentifier:@"AccTypeCell"];
    }
    return _collectionView;
}

