- (void)handleSecure:(UIButton *)sender {
    _passwordTextField.secureTextEntry = !_passwordTextField.secureTextEntry;
    if (_passwordTextField.secureTextEntry) {
        [sender setBackgroundImage:[UIImage imageNamed:@"A_eye_close"] forState:UIControlStateNormal];
    } else {
        [sender setBackgroundImage:[UIImage imageNamed:@"A_eye_open"] forState:UIControlStateNormal];
    }
}

- (void)saveAccount:(UIButton *)sender {
    NSString *type = [self.typeValueLabel.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *name = [self.nameTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *account = [self.accountTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *password = [self.passwordTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *note = [self.noteTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];

    if (type.length == 0 || name.length == 0 || account.length == 0 || password.length == 0) {
        [SVProgressHUD showErrorWithStatus:NSLocalizedString(@"请填写完整信息", nil)];
        return;
    }

    self.Account.type = type;
    self.Account.name = name;
    self.Account.account = account;
    self.Account.password = password;
    self.Account.note = note;
    self.Account.updateTime = [NSDate date];



    if (self.isNewAcc) {
        self.Account.createTime = [NSDate date];
        [AccountModel addAcc:self.Account];
        [[NSNotificationCenter defaultCenter] postNotificationName:@"AccountDataUpdated" object:nil];
        [[NSNotificationCenter defaultCenter] postNotificationName:@"SwitchToAccountTab" object:nil];
    } else {
        [AccountModel updateAcc:self.Account];
        [[NSNotificationCenter defaultCenter] postNotificationName:@"AccountDataUpdated" object:nil];
        [self dismissViewControllerAnimated:YES completion:nil];
    }


    [self dismissViewControllerAnimated:YES completion:nil];
}

- (void)deleteAccount:(UIButton *)sender {
    NSLog(@"shanchu")
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"删除"
                                                                   message:@"确定要删除此账号吗？"
                                                            preferredStyle:UIAlertControllerStyleAlert];
    [alert addAction:[UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleDefault handler:nil]];
    [alert addAction:[UIAlertAction actionWithTitle:@"删除" style:UIAlertActionStyleDestructive handler:^(UIAlertAction * _Nonnull action){
        [AccountModel deleteAcc:self.Account.accId];
        [[NSNotificationCenter defaultCenter] postNotificationName:@"AccountDataUpdated" object:nil];
        [self dismissViewControllerAnimated:YES completion:nil];
    }]];
    [self presentViewController:alert animated:YES completion:nil];
}
- (void)read {
    if (self.passwordTextField.text.length == 0) return;

    // 停止上一次的播放（立即停止，不保留队列）
    if (self.speechSynthesizer.isSpeaking) {
        [self.speechSynthesizer stopSpeakingAtBoundary:AVSpeechBoundaryImmediate];
    }

    // 确保音频会话可用
    AVAudioSession *audioSession = [AVAudioSession sharedInstance];
    [audioSession setCategory:AVAudioSessionCategoryPlayback error:nil];
    [audioSession setActive:YES error:nil];

    NSString *text = self.passwordTextField.text;

    NSMutableString *letterByLetterText = [NSMutableString string];
    for (NSUInteger i = 0; i < text.length; i++) {
        unichar c = [text characterAtIndex:i];
        [letterByLetterText appendFormat:@"%C ", c];
    }

    AVSpeechUtterance *utterance = [[AVSpeechUtterance alloc] initWithString:letterByLetterText];
    utterance.voice = [AVSpeechSynthesisVoice voiceWithIdentifier:@"com.apple.voice.compact.zh-CN.Tingting"];

    [self.speechSynthesizer speakUtterance:utterance];
}



