    if (!self.isNewAcc) {
        self.nameTextField.text = self.Account.name;
        self.accountTextField.text = self.Account.account;
        self.passwordTextField.text = self.Account.password;
        self.noteTextField.text = self.Account.note;
        self.deleteButton.hidden = NO;
        self.pageTitleLabel.text = @"Edit account";
    }
}

- (UIView *)createRowView {
    UIView *view = [[UIView alloc] init];
    view.backgroundColor = RGBA(242, 249, 244, 1);
    view.layer.cornerRadius = ZOOMW(21);
    view.layer.borderWidth = 1;
    view.layer.borderColor = RGBA(64, 216, 114, 0.85).CGColor;
    view.layer.masksToBounds = YES;
