- (void)loadData {
    if (self.isSearching) {
        self.displayAccs = [AccountModel allAccs];
    } else {
        NSPredicate *predicate = [NSPredicate predicateWithFormat:@"type == %@", self.text];
        self.displayAccs = [[AccountModel allAccs] filteredArrayUsingPredicate:predicate];
