- (NSString *)pageTitleText {
    NSDictionary *mapping = @{
        @"社交": @"Social account",
        @"邮箱": @"Mail account",
        @"游戏": @"Game account",
        @"工作": @"Work account",
        @"网站": @"Web account",
        @"其他": @"Other account"
    };
    return mapping[self.text] ?: [NSString stringWithFormat:@"%@ account", self.text ?: @""];
}

- (void)handleAccountUpdate {
    [self loadData];
}

- (void)backAction {
    [self dismissViewControllerAnimated:YES completion:nil];
}

- (void)toggleDeleteMode {
    if (!self.isDeleteMode) {
        self.isDeleteMode = YES;
        [self.selectedAccountIDs removeAllObjects];
        [self.bottomDeleteButton setHidden:NO];
        [self updateDeleteButtonAppearance];
        [self.collectionView reloadData];
        return;
    }

    if (self.selectedAccountIDs.count == 0) {
        return;
    }

    [self showDeleteAlert];
}

- (void)showDeleteAlert {
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Delete"
                                                                   message:@"Once deleted, the account cannot be recovered."
                                                            preferredStyle:UIAlertControllerStyleAlert];
    [alert addAction:[UIAlertAction actionWithTitle:@"Cancel" style:UIAlertActionStyleCancel handler:nil]];
    [alert addAction:[UIAlertAction actionWithTitle:@"Delete" style:UIAlertActionStyleDestructive handler:^(UIAlertAction * _Nonnull action) {
        [self deleteSelectedAccounts];
    }]];
    [self presentViewController:alert animated:YES completion:nil];
}

- (void)deleteSelectedAccounts {
    NSArray<AccountModel *> *accounts = [self.displayAccs copy];
    for (AccountModel *account in accounts) {
        if ([self.selectedAccountIDs containsObject:@(account.accId)]) {
            [AccountModel deleteAcc:account.accId];
        }
    }
    [[NSNotificationCenter defaultCenter] postNotificationName:@"AccountDataUpdated" object:nil];
    self.isDeleteMode = NO;
    [self.selectedAccountIDs removeAllObjects];
    self.bottomDeleteButton.hidden = YES;
    [self updateDeleteButtonAppearance];
    [self loadData];
}

- (void)bottomDeleteAction {
    if (self.selectedAccountIDs.count == 0) {
        return;
    }
    [self showDeleteAlert];
}

- (void)updateDeleteButtonAppearance {
    self.bottomDeleteButton.enabled = self.selectedAccountIDs.count > 0;
    self.bottomDeleteButton.hidden = !self.isDeleteMode;
    self.bottomDeleteButton.alpha = self.selectedAccountIDs.count > 0 ? 1.0 : 0.5;
}

#pragma mark - UICollectionView

- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.displayAccs.count;
}

- (__kindof UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    AccCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"AccCell" forIndexPath:indexPath];
    AccountModel *account = self.displayAccs[indexPath.item];
    BOOL selected = [self.selectedAccountIDs containsObject:@(account.accId)];
    [cell configureWithAccount:account deleteMode:self.isDeleteMode selectedForDelete:selected];
    return cell;
}

- (void)collectionView:(UICollectionView *)collectionView didSelectItemAtIndexPath:(NSIndexPath *)indexPath {
    AccountModel *account = self.displayAccs[indexPath.item];

    if (self.isDeleteMode) {
        NSNumber *accountID = @(account.accId);
        if ([self.selectedAccountIDs containsObject:accountID]) {
            [self.selectedAccountIDs removeObject:accountID];
        } else {
            [self.selectedAccountIDs addObject:accountID];
        }
        [self updateDeleteButtonAppearance];
        [collectionView reloadItemsAtIndexPaths:@[indexPath]];
        return;
    }

    AccountAddViewController *addVC = [[AccountAddViewController alloc] initWithAccount:account];
    [self presentViewController:addVC animated:YES completion:nil];
}

