@implementation PlayView

+ (void)initialize {
    if (self == [PlayView class]) {
        kPlayModes = @[
            @{@"name": @"雪", @"file": @"踩雪声.mp3", @"button": @"_xueshanbotton"},
            @{@"name": @"夜", @"file": @"夜间昆虫-mp3.mp3", @"button": @"_jingmibotton"},
            @{@"name": @"草原", @"file": @"放牛 哞哞叫-mp3.mp3", @"button": @"_caoyuanbotton"},
        ];
