}

- (instancetype)init {
    self = [super init];
    if (self) {
        _currentModeIndex = 0;
        [self setUpUI];
        [self setUpEvents];
    }
    return self;
}

#pragma mark - ui事件

//接收播放完成的通知
- (void)runLoopTheMovie:(NSNotification *)notification {
    NSURL *url = [[NSBundle mainBundle] URLForResource:_modeview.mode withExtension:nil];
    self.player = [AVPlayer playerWithPlayerItem:[AVPlayerItem playerItemWithURL:url]];
    [_player play];
    [self updateButtonPlayState:YES];
}

- (void)updateButtonPlayState:(BOOL)isPlaying {
    UIImage *image;
    if (@available(iOS 13.0, *)) {
        UIImageSymbolConfiguration *config = [UIImageSymbolConfiguration configurationWithPointSize:ZOOM(24) weight:UIImageSymbolWeightMedium];
        NSString *symbolName = isPlaying ? @"pause.fill" : @"play.fill";
        image = [[UIImage systemImageNamed:symbolName withConfiguration:config] imageWithTintColor:RGB(51, 51, 51) renderingMode:UIImageRenderingModeAlwaysOriginal];
    } else {
        image = isPlaying ? [UIImage imageNamed:@"A_Selectedplay"] : [UIImage imageNamed:@"A_Selectedpause"];
    }
    _modeview.Selected1.image = image;
    _modeview.Selected2.image = image;
    _modeview.Selected3.image = image;
}


