#import "PlayView.h"
#import "PrefixHeader.h"

@interface PlayView ()

@property (nonatomic, strong) UILabel *titleLabel;
@property (nonatomic, strong) UIButton *switchButton;

@property (nonatomic, strong) UIView *snowCard;
@property (nonatomic, strong) UIView *nightCard;
@property (nonatomic, strong) UIView *wavesCard;

@property (nonatomic, strong) UILabel *snowTitleLabel;
@property (nonatomic, strong) UILabel *nightTitleLabel;
@property (nonatomic, strong) UILabel *wavesTitleLabel;

@property (nonatomic, strong) UIImageView *snowImageView;
@property (nonatomic, strong) UIImageView *nightImageView;
@property (nonatomic, strong) UIImageView *wavesImageView;

@property (nonatomic, strong) UIButton *snowPlayButton;
@property (nonatomic, strong) UIButton *nightPlayButton;
@property (nonatomic, strong) UIButton *wavesPlayButton;

@property (nonatomic, strong) AVPlayer *player;
@property (nonatomic, strong) id playEndObserver;
@property (nonatomic, assign) NSInteger currentModeIndex;
@property (nonatomic, assign) BOOL isPlaying;

@end

static NSArray<NSDictionary *> *kSleepModes = nil;

@implementation PlayView

+ (void)initialize {
    if (self == [PlayView class]) {
        kSleepModes = @[
            @{ @"title" : @"Heavy\nsnow", @"image" : @"A_snow", @"file" : @"踩雪声.mp3" },
            @{ @"title" : @"Quiet\nnight", @"image" : @"A_silent night", @"file" : @"夜间昆虫-mp3.mp3" },
            @{ @"title" : @"Surging\nwaves", @"image" : @"A_Grassland", @"file" : @"海浪声.mp3" }
        ];
    }
}

- (instancetype)init {
    self = [super init];
    if (self) {
        self.backgroundColor = CLEAR_COLOR;
        self.currentModeIndex = 0;
        self.isPlaying = NO;
        [self setupUI];
        [self updateUIForCurrentMode];
        [self addPlayEndObserver];
    }
    return self;
}

- (void)dealloc {
    if (self.playEndObserver) {
        [[NSNotificationCenter defaultCenter] removeObserver:self.playEndObserver];
    }
}

#pragma mark - UI

- (void)setupUI {
    [self addSubview:self.titleLabel];
    [self addSubview:self.switchButton];

    [self addSubview:self.snowCard];
    [self addSubview:self.nightCard];
    [self addSubview:self.wavesCard];

    [self.snowCard addSubview:self.snowTitleLabel];
    [self.snowCard addSubview:self.snowImageView];
    [self.snowImageView addSubview:self.snowPlayButton];

    [self.nightCard addSubview:self.nightTitleLabel];
    [self.nightCard addSubview:self.nightImageView];
    [self.nightImageView addSubview:self.nightPlayButton];

    [self.wavesCard addSubview:self.wavesTitleLabel];
    [self.wavesCard addSubview:self.wavesImageView];
    [self.wavesImageView addSubview:self.wavesPlayButton];

    [self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.mas_safeAreaLayoutGuideTop).offset(ZOOMW(6));
        make.centerX.equalTo(self);
    }];

    [self.switchButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.titleLabel);
        make.right.equalTo(self).offset(ZOOMW(-14));
    }];

    [self.snowCard mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.titleLabel.mas_bottom).offset(ZOOMW(22));
        make.left.equalTo(self).offset(ZOOMW(10));
        make.right.equalTo(self).offset(ZOOMW(-10));
        make.height.mas_equalTo(ZOOMW(108));
    }];

    [self.nightCard mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.snowCard.mas_bottom).offset(ZOOMW(16));
        make.left.right.height.equalTo(self.snowCard);
    }];

    [self.wavesCard mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.nightCard.mas_bottom).offset(ZOOMW(16));
        make.left.right.height.equalTo(self.snowCard);
        make.bottom.lessThanOrEqualTo(self).offset(ZOOMW(-20));
    }];

    [self setupConstraintsForCard:self.snowCard titleLabel:self.snowTitleLabel imageView:self.snowImageView playButton:self.snowPlayButton];
    [self setupConstraintsForCard:self.nightCard titleLabel:self.nightTitleLabel imageView:self.nightImageView playButton:self.nightPlayButton];
    [self setupConstraintsForCard:self.wavesCard titleLabel:self.wavesTitleLabel imageView:self.wavesImageView playButton:self.wavesPlayButton];
}

- (void)setupConstraintsForCard:(UIView *)card titleLabel:(UILabel *)titleLabel imageView:(UIImageView *)imageView playButton:(UIButton *)playButton {
    [titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(card).offset(ZOOMW(24));
        make.centerY.equalTo(card);
        make.width.mas_equalTo(ZOOMW(62));
    }];

    [imageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(card).offset(ZOOMW(8));
        make.bottom.equalTo(card).offset(ZOOMW(-8));
        make.left.equalTo(titleLabel.mas_right).offset(ZOOMW(12));
        make.right.equalTo(card).offset(ZOOMW(-8));
    }];

    [playButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.center.equalTo(imageView);
        make.width.height.mas_equalTo(ZOOMW(42));
    }];
}

#pragma mark - Actions

- (void)handlePlayButtonTap:(UIButton *)sender {
    NSInteger tappedIndex = sender.tag;

    if (self.currentModeIndex == tappedIndex) {
        if (self.isPlaying) {
            [self.player pause];
            self.isPlaying = NO;
        } else {
            [self.player play];
            self.isPlaying = YES;
        }
        [self updateUIForCurrentMode];
        return;
    }

    self.currentModeIndex = tappedIndex;
    [self playCurrentMode];
}

- (void)switchToNextMode {
    self.currentModeIndex = (self.currentModeIndex + 1) % kSleepModes.count;
    [self playCurrentMode];
}

- (void)playCurrentMode {
    NSDictionary *mode = kSleepModes[self.currentModeIndex];
    NSString *fileName = mode[@"file"];
    NSURL *url = [[NSBundle mainBundle] URLForResource:fileName withExtension:nil];
    if (!url) {
        return;
    }

    [self.player pause];
    self.player = [AVPlayer playerWithURL:url];
    [self prepareAudioSession];
    [self.player play];
    self.isPlaying = YES;
    [self updateUIForCurrentMode];
}

- (void)prepareAudioSession {
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        AVAudioSession *audioSession = [AVAudioSession sharedInstance];
        [audioSession setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:nil];
        [audioSession setActive:YES error:nil];
    });
}

- (void)addPlayEndObserver {
    __weak typeof(self) weakSelf = self;
    self.playEndObserver = [[NSNotificationCenter defaultCenter] addObserverForName:AVPlayerItemDidPlayToEndTimeNotification object:nil queue:NSOperationQueue.mainQueue usingBlock:^(NSNotification * _Nonnull note) {
        if (note.object == weakSelf.player.currentItem) {
            [weakSelf.player seekToTime:kCMTimeZero];
            [weakSelf.player play];
            weakSelf.isPlaying = YES;
            [weakSelf updateUIForCurrentMode];
        }
    }];
}

#pragma mark - UI State

- (void)updateUIForCurrentMode {
    NSArray<UIButton *> *buttons = @[self.snowPlayButton, self.nightPlayButton, self.wavesPlayButton];
    [buttons enumerateObjectsUsingBlock:^(UIButton * _Nonnull button, NSUInteger idx, BOOL * _Nonnull stop) {
        NSString *imageName = @"A_Selectedplay";
        if (idx == self.currentModeIndex && self.isPlaying) {
            imageName = @"A_Selectedpause";
        }
        [button setImage:[UIImage imageNamed:imageName] forState:UIControlStateNormal];
    }];
}

#pragma mark - Factory

- (UIView *)createCardView {
    UIView *view = [[UIView alloc] init];
    view.backgroundColor = RGBA(242, 249, 244, 1);
    view.layer.cornerRadius = ZOOMW(24);
    view.layer.borderWidth = 1;
    view.layer.borderColor = RGBA(64, 216, 114, 0.85).CGColor;
    view.layer.masksToBounds = YES;
    return view;
}

- (UILabel *)createTitleLabelWithText:(NSString *)text {
    UILabel *label = [[UILabel alloc] init];
    label.text = text;
    label.numberOfLines = 2;
    label.font = KEEPASS_FONT_Regular(16);
    label.textColor = RGBA(40, 40, 40, 1);
    return label;
}

- (UIImageView *)createImageViewWithName:(NSString *)imageName {
    UIImageView *imageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:imageName]];
    imageView.contentMode = UIViewContentModeScaleAspectFill;
    imageView.layer.cornerRadius = ZOOMW(14);
    imageView.layer.masksToBounds = YES;
    imageView.userInteractionEnabled = YES;
    return imageView;
}

- (UIButton *)createPlayButtonWithTag:(NSInteger)tag {
    UIButton *button = [UIButton buttonWithType:UIButtonTypeCustom];
    button.tag = tag;
    [button addTarget:self action:@selector(handlePlayButtonTap:) forControlEvents:UIControlEventTouchUpInside];
    return button;
}

#pragma mark - Lazy Load

- (UILabel *)titleLabel {
    if (!_titleLabel) {
        _titleLabel = [[UILabel alloc] init];
