- (UIImageView *)createImageViewWithName:(NSString *)imageName {
    UIImageView *imageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:imageName]];
    imageView.contentMode = UIViewContentModeScaleAspectFill;
    imageView.layer.cornerRadius = ZOOMW(14);
    imageView.layer.masksToBounds = YES;
    imageView.userInteractionEnabled = YES;
    return imageView;
}

- (UIButton *)createPlayButtonWithTag:(NSInteger)tag {
    UIButton *button = [UIButton buttonWithType:UIButtonTypeCustom];
    button.tag = tag;
    [button addTarget:self action:@selector(handlePlayButtonTap:) forControlEvents:UIControlEventTouchUpInside];
