#pragma mark - Actions

- (void)handlePlayButtonTap:(UIButton *)sender {
    NSInteger tappedIndex = sender.tag;
    if (self.currentModeIndex == tappedIndex) {
        if (self.isPlaying) {
            [self.player pause];
            self.isPlaying = NO;
        } else {
            if (!self.player) {
                [self playCurrentMode];
                return;
            }
            [self.player play];
            self.isPlaying = YES;
        }
        [self updateUIForCurrentMode];
        return;
    }

    self.currentModeIndex = tappedIndex;
    [self playCurrentMode];
}

- (void)switchToNextMode {
    self.currentModeIndex = (self.currentModeIndex + 1) % kSleepModes.count;
    [self playCurrentMode];
}

#pragma mark - Player

- (void)playCurrentMode {
    NSDictionary *mode = kSleepModes[self.currentModeIndex];
    NSString *fileName = mode[@"file"];
    NSURL *url = [[NSBundle mainBundle] URLForResource:fileName withExtension:nil];
    if (!url) {
        self.isPlaying = NO;
        [self updateUIForCurrentMode];
        return;
    }

    [self.player pause];
    self.player = [AVPlayer playerWithURL:url];
    [self prepareAudioSession];
    [self.player play];
    self.isPlaying = YES;
    [self updateUIForCurrentMode];
}

- (void)prepareAudioSession {
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        AVAudioSession *audioSession = [AVAudioSession sharedInstance];
        [audioSession setCategory:AVAudioSessionCategoryPlayback
                      withOptions:AVAudioSessionCategoryOptionMixWithOthers
                            error:nil];
        [audioSession setActive:YES error:nil];
    });
}

- (void)addPlayEndObserver {
    __weak typeof(self) weakSelf = self;
    self.playEndObserver = [[NSNotificationCenter defaultCenter] addObserverForName:AVPlayerItemDidPlayToEndTimeNotification
                                                                              object:nil
                                                                               queue:NSOperationQueue.mainQueue
                                                                          usingBlock:^(NSNotification * _Nonnull note) {
        if (note.object != weakSelf.player.currentItem) {
            return;
        }
        [weakSelf.player seekToTime:kCMTimeZero];
        [weakSelf.player play];
        weakSelf.isPlaying = YES;
        [weakSelf updateUIForCurrentMode];
    }];
}

#pragma mark - UI State

- (void)updateUIForCurrentMode {
    NSArray<UIButton *> *buttons = @[ self.snowPlayButton, self.nightPlayButton, self.wavesPlayButton ];
    [buttons enumerateObjectsUsingBlock:^(UIButton * _Nonnull button, NSUInteger idx, BOOL * _Nonnull stop) {
        NSString *imageName = @"A_Selectedplay";
        if (idx == self.currentModeIndex && self.isPlaying) {
            imageName = @"A_Selectedpause";
        }
        [button setImage:[UIImage imageNamed:imageName] forState:UIControlStateNormal];
    }];
}

