@property(strong, nonatomic) ShowHeaderView *headerView;

@end



@implementation D5PwdToolViewController

- (instancetype)init {
    self = [super init];
    if (self) {
        // 设置modal出来的模式是占满全屏幕
        self.modalPresentationStyle = UIModalPresentationFullScreen;
    }
    return self;
}

- (void)loadView {
    [super loadView];
    [self setUpUI];

    // 创建一个 UIView，并设置其为渐变背景色
    UIView *gradientView = [[UIView alloc] initWithFrame:self.view.bounds];
    gradientView.autoresizingMask = UIViewAutoresizingFlexibleWidth | UIViewAutoresizingFlexibleHeight;

    CAGradientLayer *gradientLayer = [CAGradientLayer layer];
    gradientLayer.frame = gradientView.bounds;
    gradientLayer.colors = @[
        (__bridge id)BACKGROUND_COLOR.CGColor,
        (__bridge id)BACKGROUND_COLOR.CGColor
    ];
    gradientLayer.startPoint = CGPointMake(0.5, 0);
    gradientLayer.endPoint = CGPointMake(0.5, 1);

    // 将 gradientLayer 添加到 gradientView 的 layer 中
    [gradientView.layer insertSublayer:gradientLayer atIndex:0];

    // 将这个带有渐变色的 UIView 添加到 view 的最底层
    [self.view insertSubview:gradientView atIndex:0];
}

- (void)viewDidLoad {
    [super viewDidLoad];
}

- (void)viewDidAppear:(BOOL)animated {
    [_headerView showAppearAnimation];
}

#pragma mark - setUpUI
- (void)setUpUI {
    self.view.backgroundColor = KEEPASS_COLOR_BACKGROUND;

    [self.view addSubview:self.headerView];
    [_headerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view);
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.view).offset(ZOOM(-724));
    }];

    [self.view addSubview:self.toolView];//这里不能是_tableview，要是self才会去懒加载

    [_toolView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.headerView.mas_bottom).offset(ZOOM(20));
//        make.top.equalTo(self.view).offset(ZOOM(16));
        make.bottom.equalTo(self.view).offset(ZOOM(455));
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
    }];
}

#pragma mark - 懒加载

- (ShowHeaderView *)headerView {
    if (_headerView == nil) {
        _headerView = [[ShowHeaderView alloc] init];
        _headerView.titleLabel.text = @"密码生成器";
//        _headerView.titleLabel.text = @"";
    }
    return _headerView;
}

