    [_xueshanCard mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.left.equalTo(self);
        make.width.mas_equalTo(cardW);
    }];

    [_xueshanTitle mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(_xueshanCard).offset(ZOOM(12));
        make.left.equalTo(_xueshanCard).offset(ZOOMW(12));
        make.right.equalTo(_xueshanCard).offset(-ZOOMW(12));
    }];

    [_xueshanSubtitle mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(_xueshanTitle.mas_bottom).offset(ZOOM(4));
        make.left.equalTo(_xueshanCard).offset(ZOOMW(12));
        make.right.equalTo(_xueshanCard).offset(-ZOOMW(12));
    }];

    [_xueshanbotton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(_xueshanSubtitle.mas_bottom).offset(ZOOM(10));
        make.left.right.equalTo(_xueshanCard);
        make.height.mas_equalTo(cardW);
        make.bottom.equalTo(_xueshanCard);
    }];

    [_playBg1 mas_makeConstraints:^(MASConstraintMaker *make) {
        make.center.equalTo(_xueshanbotton);
        make.width.height.mas_equalTo(playSize);
    }];

    [_Selected1 mas_makeConstraints:^(MASConstraintMaker *make) {
        make.center.equalTo(_playBg1);
        make.width.height.mas_equalTo(ZOOM(28));
    }];

    // ---- 卡片2: 静谧的夜 ----
    [_jingmiCard mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self);
        make.left.equalTo(_xueshanCard.mas_right).offset(gap);
        make.width.mas_equalTo(cardW);
    }];

    [_jingmiTitle mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(_jingmiCard).offset(ZOOM(12));
        make.left.equalTo(_jingmiCard).offset(ZOOMW(12));
        make.right.equalTo(_jingmiCard).offset(-ZOOMW(12));
    }];

    [_jingmiSubtitle mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(_jingmiTitle.mas_bottom).offset(ZOOM(4));
        make.left.equalTo(_jingmiCard).offset(ZOOMW(12));
        make.right.equalTo(_jingmiCard).offset(-ZOOMW(12));
    }];

    [_jingmibotton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(_jingmiSubtitle.mas_bottom).offset(ZOOM(10));
        make.left.right.equalTo(_jingmiCard);
        make.height.mas_equalTo(cardW);
        make.bottom.equalTo(_jingmiCard);
    }];

    [_playBg2 mas_makeConstraints:^(MASConstraintMaker *make) {
        make.center.equalTo(_jingmibotton);
        make.width.height.mas_equalTo(playSize);
    }];

    [_Selected2 mas_makeConstraints:^(MASConstraintMaker *make) {
        make.center.equalTo(_playBg2);
        make.width.height.mas_equalTo(ZOOM(28));
    }];

    // ---- 卡片3: 碧绿的草原 ----
    [_caoyuanCard mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self);
        make.left.equalTo(_jingmiCard.mas_right).offset(gap);
        make.width.mas_equalTo(cardW);
        make.right.lessThanOrEqualTo(self);
    }];

    [_caoyuanTitle mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(_caoyuanCard).offset(ZOOM(12));
        make.left.equalTo(_caoyuanCard).offset(ZOOMW(12));
        make.right.equalTo(_caoyuanCard).offset(-ZOOMW(12));
    }];

    [_caoyuanSubtitle mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(_caoyuanTitle.mas_bottom).offset(ZOOM(4));
        make.left.equalTo(_caoyuanCard).offset(ZOOMW(12));
        make.right.equalTo(_caoyuanCard).offset(-ZOOMW(12));
    }];

    [_caoyuanbotton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(_caoyuanSubtitle.mas_bottom).offset(ZOOM(10));
        make.left.right.equalTo(_caoyuanCard);
        make.height.mas_equalTo(cardW);
        make.bottom.equalTo(_caoyuanCard);
    }];

    [_playBg3 mas_makeConstraints:^(MASConstraintMaker *make) {
        make.center.equalTo(_caoyuanbotton);
        make.width.height.mas_equalTo(playSize);
    }];

    [_Selected3 mas_makeConstraints:^(MASConstraintMaker *make) {
        make.center.equalTo(_playBg3);
        make.width.height.mas_equalTo(ZOOM(28));
    }];
}

