#pragma mark - 工厂方法

- (UIView *)createCardContainer {
    UIView *card = [[UIView alloc] init];
    card.backgroundColor = WHITE_COLOR;
    card.layer.cornerRadius = ZOOMW(16);
    card.layer.masksToBounds = YES;
    return card;
}

- (UILabel *)createTitleLabelWithText:(NSString *)text {
    UILabel *label = [[UILabel alloc] init];
    label.text = text;
    label.font = [UIFont fontWithName:@"PingFangSC-Medium" size:20];
    label.textColor = RGB(51, 51, 51);
    return label;
}

- (UILabel *)createSubtitleLabelWithText:(NSString *)text {
    UILabel *label = [[UILabel alloc] init];
    label.text = text;
    label.font = KEEPASS_FONT(14);
    label.textColor = RGB(153, 153, 153);
    return label;
}

- (UIButton *)createImageButtonWithImage:(NSString *)imageName {
    UIButton *button = [UIButton buttonWithType:UIButtonTypeCustom];
    [button setBackgroundImage:[UIImage imageNamed:imageName] forState:UIControlStateNormal];
    button.clipsToBounds = YES;
    [button addTarget:self action:@selector(modeShouldUpdate:) forControlEvents:UIControlEventTouchUpInside];
    return button;
}

- (UIView *)createPlayBackground {
    UIView *bg = [[UIView alloc] init];
    bg.backgroundColor = [UIColor colorWithWhite:1.0 alpha:0.85];
    bg.layer.cornerRadius = ZOOM(32);
    bg.userInteractionEnabled = NO;
    return bg;
}

- (UIImageView *)createPlayIcon {
    UIImageView *iv = [[UIImageView alloc] init];
    iv.contentMode = UIViewContentModeScaleAspectFit;
    if (@available(iOS 13.0, *)) {
        UIImageSymbolConfiguration *config = [UIImageSymbolConfiguration configurationWithPointSize:ZOOM(24) weight:UIImageSymbolWeightMedium];
        iv.image = [[UIImage systemImageNamed:@"play.fill" withConfiguration:config] imageWithTintColor:RGB(51, 51, 51) renderingMode:UIImageRenderingModeAlwaysOriginal];
    } else {
        iv.image = [UIImage imageNamed:@"A_Selectedpause"];
    }
    iv.hidden = YES;
    return iv;
}

@end

